import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Input, icon } from 'decantr/components';

code.example:
function BlockToolbar({ position, activeFormats = [], onFormat, onLink, onComment, onClose }) {
  const { div, span, input, button } = tags;
  const [showLinkInput, setShowLinkInput] = createSignal(false);
  const [linkUrl, setLinkUrl] = createSignal('');

  const formatButtons = [
    { id: 'bold', icon: 'bold', command: 'bold', shortcut: 'Cmd+B' },
    { id: 'italic', icon: 'italic', command: 'italic', shortcut: 'Cmd+I' },
    { id: 'underline', icon: 'underline', command: 'underline', shortcut: 'Cmd+U' },
    { id: 'strikethrough', icon: 'strikethrough', command: 'strikeThrough', shortcut: null },
    { id: 'code', icon: 'code', command: 'code', shortcut: 'Cmd+E' },
  ];

  const handleLinkSubmit = () => {
    if (linkUrl()) {
      onLink(linkUrl());
      setLinkUrl('');
      setShowLinkInput(false);
    }
  };

  // Position toolbar above selection, centered
  const style = `
    position: absolute;
    top: ${position.y - 48}px;
    left: ${position.x}px;
    transform: translateX(-50%);
  `;

  return div({ class: css('_absolute _z[100]'), style },
    div({ class: css('_flex _aic _gap0.5 _p1 _bg[var(--surface)] _shadow _r2 _border') },
      // Format buttons
      ...formatButtons.map(btn =>
        button({
          class: css(`_p1.5 _r1 _trans ${activeFormats.includes(btn.id) ? '_bg[var(--primary)/10] _fg[var(--primary)]' : '_hover:bg[var(--surface-raised)]'}`),
          onclick: () => onFormat(btn.command),
          title: btn.shortcut || btn.id
        }, icon(btn.icon, { size: '16' }))
      ),
      // Divider
      div({ class: css('_w[1px] _h5 _bg[var(--border)] _mx1') }),
      // Link button
      button({
        class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'),
        onclick: () => setShowLinkInput(!showLinkInput())
      }, icon('link', { size: '16' })),
      // Highlight
      button({
        class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'),
        onclick: () => onFormat('highlight')
      }, icon('highlighter', { size: '16' })),
      // Divider
      div({ class: css('_w[1px] _h5 _bg[var(--border)] _mx1') }),
      // Comment button
      button({
        class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'),
        onclick: onComment
      }, icon('message-square', { size: '16' }))
    ),
    // Link input popover
    showLinkInput() ? div({
      class: css('_absolute _top[100%] _left[50%] _-translate-x[50%] _mt2 _p2 _bg[var(--surface)] _shadow _r2 _border _flex _gap2')
    },
      Input({
        type: 'url',
        placeholder: 'Paste or type a link...',
        value: linkUrl(),
        onInput: (e) => setLinkUrl(e.target.value),
        onKeyDown: (e) => e.key === 'Enter' && handleLinkSubmit(),
        class: css('_w[240px]'),
        autofocus: true
      }),
      Button({ size: 'sm', onclick: handleLinkSubmit, disabled: !linkUrl() },
        icon('check', { size: '14' })
      )
    ) : null,
    // Arrow pointer
    div({ class: css('_absolute _bottom[-6px] _left[50%] _-translate-x[50%] _w3 _h3 _bg[var(--surface)] _border-b _border-r _rotate[45deg]') })
  );
}

