function ExtendedBlockToolbar({ position, activeFormats, onFormat, onColor, onAlign, onLink, onComment }) {
  const { div, button, input } = tags;
  const [showColorPicker, setShowColorPicker] = createSignal(false);

  const colors = ['#EF4444', '#F97316', '#EAB308', '#22C55E', '#3B82F6', '#8B5CF6'];

  return div({ class: css('_absolute _z[100]'), style: `top: ${position.y - 48}px; left: ${position.x}px; transform: translateX(-50%)` },
    div({ class: css('_flex _aic _gap0.5 _p1 _bg[var(--surface)] _shadow _r2 _border') },
      // Text formatting
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onFormat('bold') }, icon('bold', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onFormat('italic') }, icon('italic', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onFormat('underline') }, icon('underline', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onFormat('strikeThrough') }, icon('strikethrough', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onFormat('code') }, icon('code', { size: '16' })),
      div({ class: css('_w[1px] _h5 _bg[var(--border)] _mx1') }),
      // Color picker
      div({ class: css('_relative') },
        button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => setShowColorPicker(!showColorPicker()) },
          icon('palette', { size: '16' })
        ),
        showColorPicker() ? div({ class: css('_absolute _top[100%] _left0 _mt1 _p2 _bg[var(--surface)] _shadow _r1 _border _flex _gap1') },
          ...colors.map(c => button({
            class: css('_w6 _h6 _rfull'),
            style: `background: ${c}`,
            onclick: () => { onColor(c); setShowColorPicker(false); }
          }))
        ) : null
      ),
      div({ class: css('_w[1px] _h5 _bg[var(--border)] _mx1') }),
      // Alignment
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onAlign('left') }, icon('align-left', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onAlign('center') }, icon('align-center', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: () => onAlign('right') }, icon('align-right', { size: '16' })),
      div({ class: css('_w[1px] _h5 _bg[var(--border)] _mx1') }),
      // Link and comment
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: onLink }, icon('link', { size: '16' })),
      button({ class: css('_p1.5 _r1 _hover:bg[var(--surface-raised)]'), onclick: onComment }, icon('message-square', { size: '16' }))
    )
  );
}

